const Web3 = require('web3');
const fs = require('fs');

const RPC_HTTP_URL = process.env.RPC_HTTP_URL || '';
const RPC_WS_URL = process.env.RPC_WS_URL || '';
const PRIVATE_KEY = process.env.PRIVATE_KEY || '';
const WALLET_ADDRESS = process.env.WALLET_ADDRESS || '';
const TARGET_CONTRACTS = (process.env.TARGET_CONTRACTS || '').split(',').map(s => s.trim().toLowerCase()).filter(Boolean);
const MIN_PROFIT_WEI = BigInt(process.env.MIN_PROFIT_WEI || '0');
const GAS_PRICE_BUMP_PERCENT = Number(process.env.GAS_PRICE_BUMP_PERCENT || '20');
const CHECK_INTERVAL_MS = Number(process.env.CHECK_INTERVAL_MS || '1000');

if (!RPC_WS_URL && !RPC_HTTP_URL) {
  throw new Error('RPC_HTTP_URL or RPC_WS_URL is required');
}

const web3 = new Web3(RPC_WS_URL || RPC_HTTP_URL);
const httpWeb3 = new Web3(RPC_HTTP_URL || RPC_WS_URL);

const account = PRIVATE_KEY ? httpWeb3.eth.accounts.privateKeyToAccount(PRIVATE_KEY) : null;
if (account) {
  httpWeb3.eth.accounts.wallet.add(account);
  httpWeb3.eth.defaultAccount = account.address;
}

const seen = new Map();

function now() {
  return Date.now();
}

function isTarget(tx) {
  if (!TARGET_CONTRACTS.length) return true;
  const to = (tx.to || '').toLowerCase();
  return TARGET_CONTRACTS.includes(to);
}

function txValue(tx) {
  try {
    return BigInt(tx.value || '0');
  } catch {
    return 0n;
  }
}

function gasPrice(tx) {
  try {
    if (tx.maxFeePerGas) return BigInt(tx.maxFeePerGas);
    return BigInt(tx.gasPrice || '0');
  } catch {
    return 0n;
  }
}

async function estimateProfit(tx) {
  if (!tx.to || !isTarget(tx)) return 0n;
  const value = txValue(tx);
  const gp = gasPrice(tx);
  if (value === 0n && gp === 0n) return 0n;
  const chance = (BigInt((tx.input || '').length % 100) + 1n);
  return (value / 1000n) + (gp * chance / 1000000n);
}

async function buildFrontRunTx(victimTx, profitWei) {
  if (!account) return null;

  const nonce = await httpWeb3.eth.getTransactionCount(account.address, 'pending');
  const baseGasPrice = victimTx.maxFeePerGas
    ? BigInt(victimTx.maxFeePerGas)
    : BigInt(victimTx.gasPrice || await httpWeb3.eth.getGasPrice());

  const bumpedGasPrice = (baseGasPrice * BigInt(100 + GAS_PRICE_BUMP_PERCENT)) / 100n;

  const gas = victimTx.gas ? Number(victimTx.gas) : 250000;

  const tx = {
    from: account.address,
    to: victimTx.to,
    value: '0',
    data: victimTx.input || '0x',
    gas,
    nonce,
    chainId: await httpWeb3.eth.getChainId()
  };

  if (victimTx.maxFeePerGas && victimTx.maxPriorityFeePerGas) {
    const baseMaxPriority = BigInt(victimTx.maxPriorityFeePerGas);
    tx.maxPriorityFeePerGas = '0x' + (baseMaxPriority + (baseMaxPriority / 5n) + 1n).toString(16);
    tx.maxFeePerGas = '0x' + bumpedGasPrice.toString(16);
    tx.type = 2;
  } else {
    tx.gasPrice = '0x' + bumpedGasPrice.toString(16);
  }

  return tx;
}

async function submitTx(tx) {
  const signed = await httpWeb3.eth.accounts.signTransaction(tx, PRIVATE_KEY);
  return httpWeb3.eth.sendSignedTransaction(signed.rawTransaction);
}

async function handlePendingTx(hash) {
  if (seen.has(hash)) return;
  seen.set(hash, now());

  let tx = null;
  try {
    tx = await web3.eth.getTransaction(hash);
  } catch (e) {
    return;
  }
  if (!tx) return;
  if (!isTarget(tx)) return;

  const profitWei = await estimateProfit(tx);
  if (profitWei < MIN_PROFIT_WEI) return;

  const frontRunTx = await buildFrontRunTx(tx, profitWei);
  if (!frontRunTx) return;

  try {
    const receipt = await submitTx(frontRunTx);
    fs.appendFileSync(
      'mev-bot.log',
      JSON.stringify({
        time: new Date().toISOString(),
        victimHash: tx.hash,
        submitted: receipt && receipt.transactionHash ? receipt.transactionHash : null,
        profitWei: profitWei.toString()
      }) + '\n'
    );
  } catch (e) {
    fs.appendFileSync(
      'mev-bot.log',
      JSON.stringify({
        time: new Date().toISOString(),
        victimHash: tx.hash,
        error: e && e.message ? e.message : String(e)
      }) + '\n'
    );
  }
}

async function main() {
  if (RPC_WS_URL) {
    web3.eth.subscribe('pendingTransactions', async (error, result) => {
      if (error) return;
      if (result) await handlePendingTx(result);
    });
  } else {
    setInterval(async () => {
      try {
        const block = await httpWeb3.eth.getBlock('pending', true);
        if (!block || !block.transactions) return;
        for (const tx of block.transactions) {
          if (tx && tx.hash) await handlePendingTx(tx.hash);
        }
      } catch (e) {}
    }, CHECK_INTERVAL_MS);
  }
}

process.on('unhandledRejection', () => {});
process.on('uncaughtException', () => {});

